  1→import { useTranslation } from "@/platform/i18n/useTranslation";
  2→import { useSearchBarVisibilityTransition } from "@/features/search/hooks/useSearchBarVisibilityTransition";
  3→import type { SearchQueryTag } from "@/features/search/hooks/useSearchQuery";
  4→import { useTagSuggestions } from "@/features/search/hooks/useTagSuggestions";
  5→import type { TagId } from "@/lib/types/primitives";
  6→import type { Tag } from "@/lib/types/tag";
  7→import { LiquidGlassInput, LiquidGlassSuggestions } from "liquid-glass";
  8→import { useCallback, useEffect, useMemo, useState, type JSX } from "react";
  9→import { StyleSheet, View, type ViewStyle } from "react-native";
 10→import Animated from "react-native-reanimated";
 11→
 12→const SEARCH_INPUT_HEIGHT = 48;
 13→const SUGGESTIONS_GAP = 8;
 14→const SUGGESTION_ROW_HEIGHT = 40;
 15→const MIN_SUGGESTIONS_WIDTH = 180;
 16→const MAX_SUGGESTIONS_WIDTH = 320;
 17→
 18→export function SearchBar({
 19→  selectedTags,
 20→  freeText,
 21→  suggestionPrefix,
 22→  allTags,
 23→  onChangeFreeText,
 24→  onAddTagFromSuggestion,
 25→  onRemoveSelectedTag,
 26→  onClearQuery,
 27→  blocked = false,
 28→  isFocused,
 29→  onFocus,
 30→  onBlur,
 31→  onSubmitEditing,
 32→  style,
 33→}: {
 34→  selectedTags: Array<SearchQueryTag>;
 35→  freeText: string;
 36→  suggestionPrefix: string;
 37→  allTags: Array<Tag>;
 38→  onChangeFreeText: (text: string) => void;
 39→  onAddTagFromSuggestion: (tag: Tag, displayLabel?: string) => void;
 40→  onRemoveSelectedTag: (tagId: TagId) => void;
 41→  onClearQuery: () => void;
 42→  blocked?: boolean;
 43→  isFocused?: boolean;
 44→  onFocus?: () => void;
 45→  onBlur?: () => void;
 46→  onSubmitEditing?: () => void;
 47→  style?: ViewStyle;
 48→}): JSX.Element {
 49→  const { t } = useTranslation();
 50→  const { containerStyle } = useSearchBarVisibilityTransition(blocked);
 51→  const [isInputFocused, setIsInputFocused] = useState(false);
 52→
 53→  const excludedTagIds = useMemo((): Array<TagId> => {
 54→    return selectedTags.map((tag) => tag.id);
 55→  }, [selectedTags]);
 56→
 57→  const { suggestions, handleSuggestionPress } = useTagSuggestions({
 58→    tags: allTags,
 59→    prefix: suggestionPrefix,
 60→    onSelectSuggestion: onAddTagFromSuggestion,
 61→    excludedTagIds,
 62→  });
 63→
 64→  const liquidSelectedTags = useMemo(() => {
 65→    return selectedTags.map((tag) => ({
 66→      id: tag.id,
 67→      label: tag.label,
 68→      accessibilityLabel: t("search.selectedPill.accessibilityLabel", {
 69→        tag: tag.label,
 70→      }),
 71→    }));
 72→  }, [selectedTags, t]);
 73→
 74→  const liquidSuggestions = useMemo(() => {
 75→    return suggestions.map((suggestion) => ({
 76→      id: suggestion.id,
 77→      label: suggestion.label,
 78→      countLabel: suggestion.countLabel,
 79→      accessibilityLabel: t("search.suggestions.accessibilityLabel", {
 80→        count: suggestion.recipeCount,
 81→        countLabel: suggestion.countLabel,
 82→        tag: suggestion.label,
 83→      }),
 84→    }));
 85→  }, [suggestions, t]);
 86→
 87→  const suggestionsPanelWidth = useMemo((): number => {
 88→    const maxLabelLength = liquidSuggestions.reduce((maxLength, suggestion) => {
 89→      return Math.max(maxLength, suggestion.label.length);
 90→    }, 0);
 91→
 92→    const estimatedWidth = maxLabelLength * 11 + 110;
 93→    return Math.max(
 94→      MIN_SUGGESTIONS_WIDTH,
 95→      Math.min(MAX_SUGGESTIONS_WIDTH, estimatedWidth)
 96→    );
 97→  }, [liquidSuggestions]);
 98→
 99→  const suggestionsPanelHeight = liquidSuggestions.length * SUGGESTION_ROW_HEIGHT;
100→  const suggestionsStyle = useMemo(
101→    (): ViewStyle => ({
102→      alignSelf: "flex-start",
103→      width: suggestionsPanelWidth,
104→      height: suggestionsPanelHeight,
105→    }),
106→    [suggestionsPanelWidth, suggestionsPanelHeight]
107→  );
108→
109→  const isSuggestionsVisible =
110→    isInputFocused &&
111→    !blocked &&
112→    freeText.trim().length > 0 &&
113→    liquidSuggestions.length > 0;
114→
115→  const handleFocus = useCallback((): void => {
116→    setIsInputFocused(true);
117→    onFocus?.();
118→  }, [onFocus]);
119→
120→  const handleBlur = useCallback((): void => {
121→    setIsInputFocused(false);
122→    onBlur?.();
123→  }, [onBlur]);
124→
125→  const handleSubmitEditing = useCallback((): void => {
126→    setIsInputFocused(false);
127→    onSubmitEditing?.();
128→  }, [onSubmitEditing]);
129→
130→  useEffect((): void => {
131→    if (isFocused === false || blocked) {
132→      setIsInputFocused(false);
133→    }
134→  }, [isFocused, blocked]);
135→
136→  return (
137→    <View style={style}>
138→      <Animated.View style={[styles.container, containerStyle]}>
139→        <LiquidGlassInput
140→          value={freeText}
141→          onChangeText={onChangeFreeText}
142→          onFocus={handleFocus}
143→          onBlur={handleBlur}
144→          placeholder={t("search.placeholder")}
145→          leadingSystemImage="magnifyingglass"
146→          showClearButton
147→          onClear={onClearQuery}
148→          variant="mixed"
149→          selectedTags={liquidSelectedTags}
150→          onTagPress={onRemoveSelectedTag}
151→          isFocused={isFocused}
152→          returnKeyType="search"
153→          onSubmitEditing={handleSubmitEditing}
154→          blurOnSubmit
155→        />
156→        <View style={styles.suggestionsLayer} pointerEvents="box-none">
157→          <LiquidGlassSuggestions
158→            visible={isSuggestionsVisible}
159→            suggestions={liquidSuggestions}
160→            onSuggestionPress={handleSuggestionPress}
161→            style={suggestionsStyle}
162→          />
163→        </View>
164→      </Animated.View>
165→    </View>
166→  );
167→}
168→
169→const styles = StyleSheet.create({
170→  container: {
171→    flex: 1,
172→    position: "relative",
173→  },
174→  suggestionsLayer: {
175→    position: "absolute",
176→    left: 0,
177→    bottom: SEARCH_INPUT_HEIGHT + SUGGESTIONS_GAP,
178→    zIndex: 20,
179→  },
180→});
181→

 1→import { useCallback, useState } from "react";
 2→import { Keyboard } from "react-native";
 3→
 4→function getRandomKey(): string {
 5→  return Math.random().toString(36).substring(2, 15);
 6→}
 7→
 8→export function useSearchFocus(): {
 9→  key: string;
10→  isFocused: boolean;
11→  handleFocus: () => void;
12→  handleBlur: () => void;
13→  handleCancel: () => void;
14→} {
15→  const [isFocused, setIsFocused] = useState(false);
16→  const [key, setKey] = useState(getRandomKey());
17→
18→  const handleFocus = useCallback(() => {
19→    setIsFocused(true);
20→  }, []);
21→
22→  const handleBlur = useCallback(() => {
23→    setIsFocused(false);
24→  }, []);
25→
26→  const handleCancel = useCallback(() => {
27→    setIsFocused(false);
28→    setKey(getRandomKey());
29→    Keyboard.dismiss();
30→  }, [setKey]);
31→
32→  return {
33→    key,
34→    isFocused,
35→    handleFocus,
36→    handleBlur,
37→    handleCancel,
38→  };
39→}
