 20→function scrollToElement(element: ScrollView, y: number, height: number) {
 21→  element.scrollTo({
 22→    y: y - height - 40,
 23→    animated: true,
 24→  });
 25→}
 26→export function MetadataFormFields({
 27→  value,
 28→  onChange,
 29→  style,
 30→  scrollViewRef,
 31→}: {
 32→  value: RecipeMetadataWrite;
 33→  onChange: (metadata: Partial<RecipeMetadataWrite>) => void;
 34→  style?: ViewStyle;
 35→  scrollViewRef: React.RefObject<ScrollView | null>;
 36→}): JSX.Element {
 37→  const { t } = useTranslation();
 38→  const tagsRef = useRef<TextInput>(null);
 39→  const titleContainerRef = useRef<View>(null);
 40→  const tagsContainerRef = useRef<View>(null);
 41→
 42→  const theme = useTheme();
 43→
 44→  const scrollToInput = useCallback(
 45→    (containerRef: React.RefObject<View | null>) => {
 46→      if (!scrollViewRef.current || !containerRef.current) {
 47→        return;
 48→      }
 49→
 50→      if (Platform.OS === "web") {
 51→        containerRef.current.measure((_x, y, _width, height) => {
 52→          scrollToElement(scrollViewRef.current!, y, height);
 53→        });
 54→
 55→        return;
 56→      }
 57→
 58→      setTimeout(() => {
 59→        const container = containerRef.current;
 60→        const scrollView = scrollViewRef.current;
 61→
 62→        if (!container || !scrollView) {
 63→          return;
 64→        }
 65→
 66→        const nativeScrollRef = scrollView.getNativeScrollRef();
 67→        if (!nativeScrollRef) {
 68→          return;
 69→        }
 70→
 71→        container.measureLayout(
 72→          nativeScrollRef as unknown as NativeMethods,
 73→          (_x, y, _width, height) => {
 74→            scrollToElement(scrollView, y, height);
 75→          },
 76→          () => {}
 77→        );
 78→      }, 100);
 79→    },
 80→    [scrollViewRef]
 81→  );
 82→
 83→  return (
 84→    <View style={[styles.container, style]}>
 85→      <View ref={titleContainerRef}>
 86→        <LiquidGlassInput
 87→          label={t("recipeForm.title.label")}
 88→          value={value.title ?? ""}
 89→          onChangeText={(text) => onChange({ title: text || undefined })}
 90→          placeholder={t("recipeForm.title.placeholder")}
 91→          variant="text"
 92→          returnKeyType="next"
 93→          onSubmitEditing={() => tagsRef.current?.focus()}
 94→          blurOnSubmit={true}
 95→          onFocus={() => scrollToInput(titleContainerRef)}
 96→        />
 97→      </View>
 98→
 99→      <View style={styles.sourceContainer}>
100→        <Text style={[styles.label, getLabelColor(theme)]}>
101→          {t("recipeForm.source.label")}
102→        </Text>
103→        <SourceSelector
104→          value={value.source ?? ""}
105→          onValueChange={(source) => onChange({ source: source || undefined })}
106→        />
107→      </View>
108→
109→      <View ref={tagsContainerRef}>
110→        <GlassLikeTagInput
111→          ref={tagsRef}
112→          tags={value.tags ?? []}
113→          onChange={(tags) => onChange({ tags: tags as Array<`#${string}`> })}
114→          onFocus={() => scrollToInput(tagsContainerRef)}
115→          label={t("recipeForm.tags.label")}
116→          placeholder={t("recipeForm.tags.placeholder")}
117→        />
118→      </View>
119→    </View>
120→  );
121→}
