 20→  onSubmitEditing,
 21→  blurOnSubmit,
 22→  multiline,
 23→  maxLength,
 24→}: LiquidGlassInputProps): JSX.Element {
 25→  const shouldShowTags = variant === "tags" || variant === "mixed";
 26→  const shouldShowTextInput = variant === "text" || variant === "mixed";
 27→  const shouldUseAccent = selectedTags.length > 0 && value.trim().length > 0;
 28→  const shouldShowClearButton = showClearButton && (value.length > 0 || selectedTags.length > 0);
 29→  const height = label ? 76 : variant === "mixed" || variant === "tags" ? 48 : 56;
 30→
