 37→        style,
 38→      ]}
 39→    >
 40→      {label && <Text style={styles.label}>{label}</Text>}
 41→      <View style={styles.row}>
 42→        {shouldShowTags && (
 43→          <View style={styles.tagsContainer}>
 44→            {selectedTags.map((tag) => (
 45→              <Pressable
 46→                key={tag.id}
 47→                onPress={onTagPress ? () => onTagPress(tag.id) : undefined}
 48→                style={[
 49→                  styles.tagPill,
 50→                  shouldUseAccent && styles.tagPillAccented,
 51→                ]}
 52→                accessibilityLabel={tag.accessibilityLabel ?? tag.label}
 53→              >
 54→                <Text style={styles.tagText}>{tag.label}</Text>
 55→              </Pressable>
 56→            ))}
 57→          </View>
 58→        )}
