 65→            onBlur={onBlur}
 66→            autoFocus={autoFocus}
 67→            returnKeyType={returnKeyType}
 68→            onSubmitEditing={onSubmitEditing}
 69→            blurOnSubmit={blurOnSubmit}
 70→            multiline={multiline}
 71→            maxLength={maxLength}
 72→            style={styles.input}
 73→            onKeyPress={(event): void => {
 74→              if (
 75→                event.nativeEvent.key === "Backspace" &&
 76→                value.length === 0 &&
 77→                selectedTags.length > 0
 78→              ) {
 79→                const lastTag = selectedTags[selectedTags.length - 1];
 80→                if (lastTag) {
 81→                  onTagPress?.(lastTag.id);
 82→                }
 83→              }
 84→            }}
 85→          />
 86→        )}
 87→        {shouldShowClearButton && (
