505→private struct BackspaceAwareTextField: UIViewRepresentable {
506→  @Binding var text: String
507→  var placeholder: String
508→  var returnKeyType: UIReturnKeyType
509→  @Binding var isFocused: Bool
510→  var blurOnSubmit: Bool
511→  var onFocus: () -> Void
512→  var onBlur: () -> Void
513→  var onSubmit: () -> Void
514→  var onEmptyBackspace: () -> Void
515→
516→  func makeUIView(context: Context) -> DeletingAwareUITextField {
517→    let textField = DeletingAwareUITextField(frame: .zero)
518→    textField.borderStyle = .none
519→    textField.font = UIFont.systemFont(ofSize: 16)
520→    textField.textColor = .label
521→    textField.backgroundColor = .clear
522→    textField.returnKeyType = returnKeyType
523→    textField.placeholder = placeholder
524→    textField.attributedPlaceholder = NSAttributedString(
525→      string: placeholder,
526→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
527→    )
528→    textField.delegate = context.coordinator
529→    textField.onEmptyBackspace = onEmptyBackspace
530→    textField.addTarget(
531→      context.coordinator,
532→      action: #selector(Coordinator.handleEditingChanged(_:)),
533→      for: .editingChanged
534→    )
535→    return textField
536→  }
537→
538→  func updateUIView(_ uiView: DeletingAwareUITextField, context: Context) {
539→    if uiView.text != text {
540→      uiView.text = text
541→    }
542→
543→    uiView.returnKeyType = returnKeyType
544→    uiView.placeholder = placeholder
545→    uiView.attributedPlaceholder = NSAttributedString(
546→      string: placeholder,
547→      attributes: [.foregroundColor: UIColor(white: 0.55, alpha: 1)]
548→    )
549→    uiView.onEmptyBackspace = onEmptyBackspace
550→
551→    if isFocused && !uiView.isFirstResponder {
552→      uiView.becomeFirstResponder()
553→    } else if !isFocused && uiView.isFirstResponder {
554→      uiView.resignFirstResponder()
555→    }
556→  }
557→
558→  func makeCoordinator() -> Coordinator {
559→    Coordinator(
560→      text: $text,
561→      isFocused: $isFocused,
562→      blurOnSubmit: blurOnSubmit,
563→      onFocus: onFocus,
564→      onBlur: onBlur,
565→      onSubmit: onSubmit
566→    )
567→  }
568→
569→  final class Coordinator: NSObject, UITextFieldDelegate {
570→    private var text: Binding<String>
571→    private var isFocused: Binding<Bool>
572→    private let blurOnSubmit: Bool
573→    private let onFocus: () -> Void
574→    private let onBlur: () -> Void
575→    private let onSubmit: () -> Void
576→
577→    init(
578→      text: Binding<String>,
579→      isFocused: Binding<Bool>,
580→      blurOnSubmit: Bool,
581→      onFocus: @escaping () -> Void,
582→      onBlur: @escaping () -> Void,
583→      onSubmit: @escaping () -> Void
584→    ) {
585→      self.text = text
586→      self.isFocused = isFocused
587→      self.blurOnSubmit = blurOnSubmit
588→      self.onFocus = onFocus
589→      self.onBlur = onBlur
590→      self.onSubmit = onSubmit
591→    }
592→
593→    @objc
594→    func handleEditingChanged(_ textField: UITextField) {
595→      text.wrappedValue = textField.text ?? ""
596→    }
597→
598→    func textFieldDidBeginEditing(_ textField: UITextField) {
599→      if !isFocused.wrappedValue {
600→        isFocused.wrappedValue = true
601→      }
602→      onFocus()
603→    }
604→
605→    func textFieldDidEndEditing(_ textField: UITextField) {
606→      if isFocused.wrappedValue {
607→        isFocused.wrappedValue = false
608→      }
609→      onBlur()
610→    }
611→
612→    func textFieldShouldReturn(_ textField: UITextField) -> Bool {
613→      onSubmit()
614→      if blurOnSubmit {
615→        isFocused.wrappedValue = false
616→        textField.resignFirstResponder()
617→      }
618→      return true
619→    }
620→  }
621→}
